func TestW3C_stream_available(t *testing.T) {
	t.Parallel()
	w3cRunTests(t, []w3cTest{
		{Name: "stream-available-001", StylesheetPath: "", InitialTemplate: "main", Params: map[string]string{"uri": "'non-existent-stream.xml'"}, Assertions: []w3cAssertion{w3cAssertXPath("/out = \"false\"")}, Skip: "no stylesheet"},
		{Name: "stream-available-002", StylesheetPath: "", InitialTemplate: "main", Params: map[string]string{"uri": "'../snapshot/snapshot-01.xml'"}, Assertions: []w3cAssertion{w3cAssertXPath("/out = \"true\"")}, Skip: "no stylesheet"},
		{Name: "stream-available-003", StylesheetPath: "", InitialTemplate: "main", Params: map[string]string{"uri": "'../unparsed-text/xiso-8859-1.txt'"}, Assertions: []w3cAssertion{w3cAssertXPath("/out = \"false\"")}, Skip: "no stylesheet"},
		{Name: "stream-available-004", StylesheetPath: "", InitialTemplate: "main", Params: map[string]string{"uri": "'unfinished.xml'"}, Assertions: []w3cAssertion{w3cAssertXPath("/out = \"true\"")}, Skip: "no stylesheet"},
		{Name: "stream-available-005", StylesheetPath: "", InitialTemplate: "main", Params: map[string]string{"uri": "'egpe.xml'"}, Assertions: []w3cAssertion{w3cAssertXPath("/out = \"true\"")}, Skip: "no stylesheet"},
		{Name: "stream-available-006", StylesheetPath: "", InitialTemplate: "main", Params: map[string]string{"uri": "'dtd-only.xml'"}, Assertions: []w3cAssertion{w3cAssertXPath("/out = \"false\"")}, Skip: "no stylesheet"},
	})
}

